using System.Windows;
using System.Windows.Documents;
using System.Windows.Media;

namespace EaxmBuilder.Controls;

public enum FluentIconKind
{
    ArrowLeft,
    ArrowRight,
    ArrowUpload,
    Checkmark,
    ChevronDown,
    ChevronUp,
    Circle,
    Dismiss,
    Document,
    DocumentPdf,
    ErrorCircle,
    FolderOpen,
    Home,
    Info,
    Maximize,
    Refresh,
    Settings,
    Subtract,
    Sync
}

public sealed class FluentIcon : FrameworkElement
{
    public static readonly DependencyProperty KindProperty = DependencyProperty.Register(
        nameof(Kind), typeof(FluentIconKind), typeof(FluentIcon),
        new FrameworkPropertyMetadata(FluentIconKind.Document, FrameworkPropertyMetadataOptions.AffectsRender));

    public static readonly DependencyProperty ForegroundProperty = TextElement.ForegroundProperty.AddOwner(
        typeof(FluentIcon),
        new FrameworkPropertyMetadata(Brushes.Black,
            FrameworkPropertyMetadataOptions.AffectsRender | FrameworkPropertyMetadataOptions.Inherits));

    public static readonly DependencyProperty RotationAngleProperty = DependencyProperty.Register(
        nameof(RotationAngle), typeof(double), typeof(FluentIcon),
        new FrameworkPropertyMetadata(0d, FrameworkPropertyMetadataOptions.AffectsRender));

    private static readonly IReadOnlyDictionary<FluentIconKind, Geometry> Geometries = CreateGeometries();

    public FluentIconKind Kind
    {
        get => (FluentIconKind)GetValue(KindProperty);
        set => SetValue(KindProperty, value);
    }

    public Brush Foreground
    {
        get => (Brush)GetValue(ForegroundProperty);
        set => SetValue(ForegroundProperty, value);
    }

    public double RotationAngle
    {
        get => (double)GetValue(RotationAngleProperty);
        set => SetValue(RotationAngleProperty, value);
    }

    protected override Size MeasureOverride(Size availableSize)
    {
        var width = double.IsNaN(Width) ? 20 : Width;
        var height = double.IsNaN(Height) ? 20 : Height;
        return new Size(width, height);
    }

    protected override void OnRender(DrawingContext drawingContext)
    {
        base.OnRender(drawingContext);
        if (ActualWidth <= 0 || ActualHeight <= 0) return;

        var geometry = Geometries[Kind].Clone();
        var size = Math.Min(ActualWidth, ActualHeight);
        var scale = size / 24d;
        var transforms = new TransformGroup();
        transforms.Children.Add(new MatrixTransform(scale, 0, 0, scale,
            (ActualWidth - size) / 2d, (ActualHeight - size) / 2d));
        if (RotationAngle != 0)
            transforms.Children.Add(new RotateTransform(RotationAngle, ActualWidth / 2d, ActualHeight / 2d));
        geometry.Transform = transforms;
        drawingContext.DrawGeometry(Foreground, null, geometry);
    }

